var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.`,JPN:`長い間悩んだ結果、あなたは一つ大事なことに気づいた。`,ENG:`After much debate, you came to the conclusion`,TWN:`苦惱許久後，你意識到一件重要的事實。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.`,JPN:`ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。`,ENG:`that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.`,TWN:`經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`그리하여 당신은 결심했다.`,JPN:`そして、あなたは決心した。`,ENG:`So, you've decided`,TWN:`所以你下定決心。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.`,JPN:`この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。`,ENG:`that you'll be with her, no matter the consequences.`,TWN:`不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.`,JPN:`意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。`,ENG:`Having decided that, you called her to your office. She said she'd be here soon.`,TWN:`做好心理準備後，你將她傳喚到老闆辦公室，他說馬上就會過來。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`JANE_MASON_NULL_NEWYEAR2022`,text:{KOREA:`어머? 간첩 노릇할 사람이라도 필요해?`,JPN:`なぁに？スパイ役でも募集してるのかしら？`,ENG:`Oh, are you looking to hire a spy? `,TWN:`哎呀？你需要有人當間諜嗎？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`JANE_MASON_NULL_NEWYEAR2022`,face:`UNIT_LAUGH`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`JANE_MASON_NULL_NEWYEAR2022`,text:{KOREA:`그래, 종신계약. 그래서 하는 말이야.`,JPN:`ええ、終身契約よね。だから訊いているのよ。`,ENG:`Yes, a lifetime contract. That's why I'm asking.`,TWN:`是嗎，終身契約啊，怪不得。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`JANE_MASON_NULL_NEWYEAR2022`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`JANE_MASON_NULL_NEWYEAR2022`,text:{KOREA:`사장님도 잘 알잖아? 나 같은 타입은 잠깐 한눈 팔면 바람처럼 사라진다는 거?`,JPN:`社長だってわかってるでしょう？　アタシのようなタイプは、ちょっとでも目を離すと風のように消えちゃうってことくらい。`,ENG:`As you know, Boss, people like me don't stay in one place for too long.`,TWN:`老闆也很清楚吧？我這種人只要稍微不留神，就會像風一樣消失喔？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`JANE_MASON_NULL_NEWYEAR2022`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`JANE_MASON_NULL_NEWYEAR2022`,text:{KOREA:`믿을 수 없는 사람에게 믿기지 않는 제안을 할 때는, 다른 꿍꿍이가 있단 뜻이지.`,JPN:`信頼の置けない相手に、信頼関係を持ちかけるということは、他に何か企みがあるってことよね？`,ENG:`You have to have a hidden agenda to offer me to stay with you for life.`,TWN:`對一個不可信的人提出不可信的提案，代表你有別的動機。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`JANE_MASON_NULL_NEWYEAR2022`,face:`UNIT_PRIDE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`JANE_MASON_NULL_NEWYEAR2022`,text:{KOREA:`......후후. 그래. 우리 사이엔 상관없는 이야기지.`,JPN:`……ふふ、そうね。今のは失言だったわ。だって、社長とアタシの仲だもの。`,ENG:`Hah hah. I know. I guess that doesn't matter between us two.`,TWN:`......呵呵，是啊，以我們的關係，這都無所謂。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`JANE_MASON_NULL_NEWYEAR2022`,face:`UNIT_LAUGH`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`JANE_MASON_NULL_NEWYEAR2022`,text:{KOREA:`하지만 나랑 엮이면 고생 깨나 한다는 건 알고 하는 소리겠지?`,JPN:`でも、アタシに付き合うと苦労するはめになるわよ。それを承知で言ってるのよね？`,ENG:`But you do know that I'm a handful, right?`,TWN:`不過和我扯上關係會很麻煩的，你是知道這件事才問我的嗎？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`JANE_MASON_NULL_NEWYEAR2022`,face:`UNIT_SERIOUS`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`JANE_MASON_NULL_NEWYEAR2022`,text:{KOREA:`그렇다고 너무 걱정은 마.`,JPN:`そうね……とりあえず、リラックスしましょう。`,ENG:`But don't worry too much.`,TWN:`但你也不用太擔心。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`JANE_MASON_NULL_NEWYEAR2022`,face:`UNIT_IDLE`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`JANE_MASON_NULL_NEWYEAR2022`,text:{KOREA:`내가 아주...... 즐겁게 해 줄 테니까.`,JPN:`社長にはとっても……楽しい思いをさせてあげる。`,ENG:`I'll keep you entertained.`,TWN:`我會......好好取悅你的。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`JANE_MASON_NULL_NEWYEAR2022`,face:`UNIT_LAUGH`},R:null}}}];export{e as default};